import { mkdir, rm, writeFile } from "node:fs/promises";
import { pages, regions, services, blogPages, site } from "../data/pages.mjs";

const root = new URL("../", import.meta.url);
const base = site.baseUrl.replace(/\/$/, "");
const generated = "Generated by scripts/generate-site.mjs from data/pages.mjs.";

function esc(value) {
  return String(value)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#39;");
}

function urlFor(slug = "") {
  return `${base}/${slug ? `${slug}/` : ""}`;
}

function pathFor(slug = "") {
  return new URL(slug ? `${slug}/index.html` : "index.html", root);
}

function pageMap() {
  return new Map(pages.map((page) => [page.slug, page]));
}

const css = `
:root{--bg:#0b1117;--ink:#f6f1e8;--muted:#d5c8b6;--sub:#aa9b86;--line:rgba(255,255,255,.16);--panel:rgba(255,255,255,.07);--gold:#d8b45b;--gold2:#f2d992;--green:#45d19d;--blue:#68a9ff}
*{box-sizing:border-box}html{scroll-behavior:smooth}body{margin:0;font-family:'DM Sans',Inter,Segoe UI,Arial,sans-serif;background:var(--bg);color:var(--ink);line-height:1.65}body:before{content:"";position:fixed;inset:0;z-index:-2;background:linear-gradient(135deg,#071018 0%,#141922 48%,#0b1117 100%)}a{color:inherit}.container{max-width:1160px;margin:0 auto;padding:0 22px}.topbar{position:sticky;top:0;z-index:10;background:rgba(11,17,23,.88);backdrop-filter:blur(18px);border-bottom:1px solid var(--line)}.nav{min-height:70px;display:flex;align-items:center;justify-content:space-between;gap:24px}.brand{display:flex;gap:12px;align-items:center;text-decoration:none;font-weight:900}.mark{width:34px;height:34px;background:linear-gradient(135deg,var(--gold),var(--gold2));clip-path:polygon(0 0,100% 0,86% 100%,0 100%)}.navlinks{display:flex;gap:18px;align-items:center}.navlinks a{text-decoration:none;color:var(--muted);font-weight:750;font-size:.94rem}.navlinks a:hover{color:#fff}.navlinks .navcta{background:var(--ink);color:#111820;padding:10px 14px}.breadcrumbs{padding:18px 22px 0;color:var(--sub);font-size:.92rem}.breadcrumbs ol{display:flex;flex-wrap:wrap;gap:8px;margin:0;padding:0;list-style:none}.breadcrumbs a{text-decoration:none;color:var(--muted)}.hero{position:relative;overflow:hidden;padding:72px 0 78px;border-bottom:1px solid var(--line);background:linear-gradient(90deg,rgba(9,14,20,.96),rgba(13,22,32,.82)),url('/static/hero_logistics.webp') center/cover no-repeat}.eyebrow{display:inline-flex;align-items:center;gap:8px;color:var(--gold2);text-transform:uppercase;letter-spacing:.12em;font-size:.75rem;font-weight:900}.eyebrow:before{content:"";width:7px;height:7px;background:var(--green)}h1{font-size:clamp(2.35rem,5.8vw,5.4rem);line-height:.98;margin:18px 0 18px;max-width:970px;letter-spacing:0;font-weight:900;text-transform:uppercase}h2{font-size:clamp(1.75rem,3.4vw,3.15rem);line-height:1.08;margin:0 0 16px;letter-spacing:0}h3{margin:0 0 8px;font-size:1.15rem}.lead{font-size:clamp(1.06rem,1.8vw,1.24rem);max-width:840px;color:var(--muted);margin:0}.actions{display:flex;flex-wrap:wrap;gap:12px;margin-top:30px}.btn{display:inline-flex;align-items:center;justify-content:center;min-height:50px;padding:13px 18px;text-decoration:none;font-weight:900}.primary{background:linear-gradient(135deg,var(--gold),var(--gold2));color:#111820}.secondary{border:1px solid rgba(255,255,255,.3);color:#fff;background:rgba(255,255,255,.05)}section{padding:72px 0}.band{border-block:1px solid var(--line);background:linear-gradient(135deg,rgba(216,180,91,.12),rgba(104,169,255,.08))}.section-head{max-width:830px;margin-bottom:28px}.grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:18px}.grid.two{grid-template-columns:repeat(2,minmax(0,1fr))}.card,.panel{border:1px solid var(--line);background:var(--panel);padding:24px}.card p,.panel p,.muted{color:var(--muted)}.list{display:grid;gap:12px;margin:16px 0 0;padding:0;list-style:none}.list li{position:relative;padding-left:22px;color:var(--muted)}.list li:before{content:"";position:absolute;left:0;top:.7em;width:8px;height:8px;background:var(--gold);transform:rotate(45deg)}.updated{color:var(--sub);font-size:.94rem;margin-top:24px}.related{display:flex;flex-wrap:wrap;gap:10px}.related a{border:1px solid var(--line);background:rgba(255,255,255,.05);padding:10px 12px;text-decoration:none;color:var(--muted);font-weight:750}.faq details{border-top:1px solid var(--line);padding:18px 0}.faq details:last-child{border-bottom:1px solid var(--line)}.faq summary{cursor:pointer;font-weight:900;color:#fff}.footer{padding:38px 0;border-top:1px solid var(--line);color:var(--sub);background:rgba(0,0,0,.18)}.footer a{color:var(--muted);text-decoration:none}@media (max-width:860px){.navlinks a{display:none}.navlinks .navcta{display:block;padding:9px 12px}.nav{gap:12px}.brand{font-size:.92rem}.grid,.grid.two{grid-template-columns:1fr}.hero{padding:52px 0 58px}section{padding:54px 0}h1{font-size:clamp(2.2rem,13vw,3.9rem)}}`.trim();

function head({ title, description, canonical, type = "website", jsonLd }) {
  return `<!doctype html>
<html lang="nl">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>${esc(title)}</title>
<meta name="description" content="${esc(description)}">
<meta name="robots" content="index, follow, max-image-preview:large">
<link rel="canonical" href="${esc(canonical)}">
<meta property="og:title" content="${esc(title)}">
<meta property="og:description" content="${esc(description)}">
<meta property="og:type" content="${esc(type)}">
<meta property="og:url" content="${esc(canonical)}">
<meta property="og:locale" content="nl_NL">
<meta property="og:image" content="${base}/static/hero_logistics.webp">
<link rel="preload" as="image" href="/static/hero_logistics.webp" type="image/webp" fetchpriority="high">
<link href="https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;650;750;900&display=swap" rel="stylesheet">
<style>${css}</style>
<script type="application/ld+json">${JSON.stringify(jsonLd)}</script>
<script defer src="/analytics.js"></script>
</head>`;
}

function shell({ title, description, canonical, jsonLd, body, breadcrumbItems }) {
  const crumbs = breadcrumbItems
    .map((item, index) => `<li>${index ? "/" : ""} ${item.url ? `<a href="${esc(item.url)}">${esc(item.name)}</a>` : esc(item.name)}</li>`)
    .join("");
  return `${head({ title, description, canonical, jsonLd })}
<body>
<!-- ${generated} -->
<header class="topbar"><div class="container nav"><a class="brand" href="/"><span class="mark"></span><span>Logistic Security</span></a><nav class="navlinks"><a href="/#diensten">Diensten</a><a href="/#regio">Regio</a><a href="/blog/">Kennisbank</a><a class="navcta" href="#contact">Contact</a></nav></div></header>
<nav class="breadcrumbs container" aria-label="Breadcrumb"><ol>${crumbs}</ol></nav>
${body}
<footer class="footer"><div class="container">© Praesidion Security B.V. · Logisticsecurity.nl voor logistieke beveiligingsvragen · <a href="/sitemap.xml">Sitemap</a> · <a href="/llms.txt">llms.txt</a></div></footer>
</body>
</html>
`;
}

function serviceGraph(page, relatedPages) {
  return {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Service",
        "@id": `${urlFor(page.slug)}#service`,
        name: page.title,
        serviceType: page.title,
        description: page.description,
        provider: { "@type": "Organization", name: site.providerName, url: site.providerUrl },
        areaServed: page.areaServed.map((name) => ({ "@type": "Place", name })),
        url: urlFor(page.slug),
        dateModified: page.updated,
        hasOfferCatalog: {
          "@type": "OfferCatalog",
          name: "Deliverables",
          itemListElement: page.approach.map((item) => ({ "@type": "Offer", itemOffered: { "@type": "Service", name: item.title, description: item.text } }))
        },
        isRelatedTo: relatedPages.map((related) => ({ "@type": "WebPage", name: related.title, url: urlFor(related.slug) }))
      },
      {
        "@type": "FAQPage",
        "@id": `${urlFor(page.slug)}#faq`,
        mainEntity: page.faq.map((item) => ({ "@type": "Question", name: item.question, acceptedAnswer: { "@type": "Answer", text: item.answer } }))
      },
      {
        "@type": "BreadcrumbList",
        "@id": `${urlFor(page.slug)}#breadcrumb`,
        itemListElement: [
          { "@type": "ListItem", position: 1, name: "Home", item: `${base}/` },
          { "@type": "ListItem", position: 2, name: page.kind === "region" ? "Regio" : "Diensten", item: `${base}/#${page.kind === "region" ? "regio" : "diensten"}` },
          { "@type": "ListItem", position: 3, name: page.title, item: urlFor(page.slug) }
        ]
      }
    ]
  };
}

function renderPage(page) {
  const bySlug = pageMap();
  const relatedPages = page.related.map((slug) => bySlug.get(slug));
  const body = `<main>
<section class="hero"><div class="container"><span class="eyebrow">${page.kind === "region" ? "Regionale logistieke beveiliging" : "Logistieke beveiligingsdienst"}</span><h1>${esc(page.title)}</h1><p class="lead">${esc(page.intro)}</p><div class="actions"><a class="btn primary" href="#contact">Bespreek beveiligingsvraag</a><a class="btn secondary" href="#aanpak">Bekijk aanpak</a></div><p class="updated">Laatst bijgewerkt: <time datetime="${esc(page.updated)}">${esc(page.updated)}</time></p></div></section>
<section><div class="container grid two"><article class="panel"><h2>Uw beveiligingsvraag</h2><p>${esc(page.intent)}</p></article><article class="panel"><h2>Werkgebied</h2><p>${page.areaServed.map(esc).join(", ")}.</p><p class="muted">De uiteindelijke inrichting volgt uit locatie, logistiek proces, tijden, risico's en verantwoordelijkheden.</p></article></div></section>
<section class="band"><div class="container"><div class="section-head"><span class="eyebrow">Lokale context</span><h2>Wat maakt deze beveiligingsvraag specifiek?</h2></div><div class="grid">${page.context.map((text) => `<article class="card"><p>${esc(text)}</p></article>`).join("")}</div></div></section>
<section><div class="container"><div class="section-head"><span class="eyebrow">Risico's</span><h2>Operationele aandachtspunten</h2></div><div class="grid">${page.risks.map((item) => `<article class="card"><h3>${esc(item.title)}</h3><p>${esc(item.text)}</p></article>`).join("")}</div></div></section>
<section id="aanpak" class="band"><div class="container"><div class="section-head"><span class="eyebrow">Aanpak en deliverables</span><h2>Van intake naar uitvoerbare instructies</h2></div><div class="grid">${page.approach.map((item) => `<article class="card"><h3>${esc(item.title)}</h3><p>${esc(item.text)}</p></article>`).join("")}</div></div></section>
<section class="faq"><div class="container"><div class="section-head"><span class="eyebrow">FAQ</span><h2>Veelgestelde vragen</h2></div>${page.faq.map((item) => `<details><summary>${esc(item.question)}</summary><p>${esc(item.answer)}</p></details>`).join("")}</div></section>
<section class="band"><div class="container"><div class="section-head"><span class="eyebrow">Verder lezen</span><h2>Gerelateerde logistieke beveiligingsvragen</h2></div><div class="related">${relatedPages.map((related) => `<a href="/${esc(related.slug)}/">${esc(related.title)}</a>`).join("")}</div></div></section>
<section id="contact"><div class="container panel"><h2>Bespreek de locatie, tijden en risico's</h2><p>Stuur adres of regio, type object, gewenste tijden, bestaande maatregelen en de belangrijkste afwijkingen in het logistieke proces. Praesidion Security werkt de mogelijke inzet uit op basis van concrete gegevens.</p><div class="actions"><a class="btn primary" href="mailto:${esc(site.email)}?subject=Aanvraag ${encodeURIComponent(page.title)}">Mail ${esc(site.email)}</a><a class="btn secondary" href="tel:${esc(site.phoneHref)}">Bel ${esc(site.phoneLabel)}</a></div></div></section>
</main>`;
  return shell({
    title: page.metaTitle,
    description: page.description,
    canonical: urlFor(page.slug),
    jsonLd: serviceGraph(page, relatedPages),
    body,
    breadcrumbItems: [{ name: "Home", url: "/" }, { name: page.kind === "region" ? "Regio" : "Diensten", url: `/#${page.kind === "region" ? "regio" : "diensten"}` }, { name: page.title }]
  });
}

function homepageGraph() {
  return {
    "@context": "https://schema.org",
    "@graph": [
      { "@type": "Organization", name: site.providerName, url: site.providerUrl },
      { "@type": "WebSite", name: site.name, url: `${base}/`, inLanguage: "nl-NL", publisher: { "@type": "Organization", name: site.providerName, url: site.providerUrl } }
    ]
  };
}

function renderHome() {
  const serviceCards = services.map((page) => `<article class="card"><h3><a href="/${esc(page.slug)}/">${esc(page.title)}</a></h3><p>${esc(page.description)}</p></article>`).join("");
  const regionCards = regions.map((page) => `<article class="card"><h3><a href="/${esc(page.slug)}/">${esc(page.title)}</a></h3><p>${esc(page.description)}</p></article>`).join("");
  const body = `<main>
<section class="hero"><div class="container"><span class="eyebrow">Logistic Security by Praesidion</span><h1>Logistieke beveiliging voor warehouses, distributiecentra en transportlocaties</h1><p class="lead">Logisticsecurity.nl bundelt logistieke beveiligingsvragen. Praesidion Security blijft de brede uitvoerende beveiligingsorganisatie; deze site richt zich op intake, context en dienstverlening voor logistieke processen.</p><div class="actions"><a class="btn primary" href="#contact">Bespreek beveiligingsvraag</a><a class="btn secondary" href="#diensten">Bekijk diensten</a></div><p class="updated">Laatst bijgewerkt: <time datetime="${esc(site.updated)}">${esc(site.updated)}</time></p></div></section>
<section id="diensten"><div class="container"><div class="section-head"><span class="eyebrow">Diensten</span><h2>Beveiliging afgestemd op het logistieke proces</h2><p class="lead">Van toegangscontrole en warehousebeveiliging tot nachtelijke terreincontrole: iedere vraag begint bij de werkelijke goederen-, personen- en voertuigstromen.</p></div><div class="grid">${serviceCards}</div></div></section>
<section id="regio" class="band"><div class="container"><div class="section-head"><span class="eyebrow">Regio</span><h2>Logistieke beveiliging per regio in Limburg</h2><p class="lead">Lees welke operationele aandachtspunten in de verschillende Limburgse logistieke gebieden een rol kunnen spelen en hoe de intake daarop wordt ingericht.</p></div><div class="grid">${regionCards}</div></div></section>
<section><div class="container grid two"><article class="panel"><h2>Van locatiebeeld naar voorstel</h2><p>Een beveiligingsvoorstel volgt na intake van locatie, proces, tijden, risico's en verantwoordelijkheden. Zo sluiten taken, instructies en rapportage aan op de dagelijkse operatie.</p></article><article class="panel"><h2>Wat levert de intake op?</h2><ul class="list"><li>Scope van terrein, gebouw en logistieke zones</li><li>Controlepunten voor toegang, docks, rondes en overdracht</li><li>Escalatie- en rapportageafspraken</li><li>Afgebakende aannames voor een inzetvoorstel</li></ul></article></div></section>
<section id="contact" class="band"><div class="container panel"><h2>Laat Praesidion Security meekijken</h2><p>Mail de locatie, gewenste tijden, type logistiek proces en bekende aandachtspunten.</p><div class="actions"><a class="btn primary" href="mailto:${esc(site.email)}">Mail ${esc(site.email)}</a><a class="btn secondary" href="tel:${esc(site.phoneHref)}">Bel ${esc(site.phoneLabel)}</a></div></div></section>
</main>`;
  return shell({
    title: "Logistieke beveiliging Limburg | Logistic Security by Praesidion",
    description: "Regionale en dienstgerichte beveiligingspagina's voor warehouses, distributiecentra, transportbedrijven en logistieke bedrijventerreinen in Limburg.",
    canonical: `${base}/`,
    jsonLd: homepageGraph(),
    body,
    breadcrumbItems: [{ name: "Home" }]
  });
}

function renderSitemap() {
  const urls = [
    { loc: `${base}/`, lastmod: site.updated, priority: "1.0", changefreq: "weekly" },
    ...pages.map((page) => ({ loc: urlFor(page.slug), lastmod: page.updated, priority: page.kind === "region" ? "0.84" : "0.82", changefreq: "monthly" })),
    ...blogPages.map((page) => ({ loc: urlFor(page.slug), lastmod: page.updated, priority: page.slug === "blog" ? "0.70" : "0.68", changefreq: page.slug === "blog" ? "weekly" : "monthly" }))
  ];
  return `<?xml version="1.0" encoding="UTF-8"?>
<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">
${urls.map((item) => `  <url><loc>${esc(item.loc)}</loc><lastmod>${esc(item.lastmod)}</lastmod><changefreq>${item.changefreq}</changefreq><priority>${item.priority}</priority></url>`).join("\n")}
</urlset>
`;
}

function renderLlms() {
  const line = (page) => `- ${page.title}: ${urlFor(page.slug)} — ${page.description}`;
  return `# logisticsecurity.nl

Logisticsecurity.nl beschrijft logistieke beveiligingsvragen voor warehouses, distributiecentra, transportbedrijven, fulfilmentlocaties en logistieke bedrijventerreinen. Praesidion Security B.V. blijft de brede uitvoerende beveiligingsorganisatie via ${site.providerUrl}; logisticsecurity.nl bezit de logistieke intenties en verwijst intakevragen door naar Praesidion.

## Regionale pagina's
${regions.map(line).join("\n")}

## Dienstpagina's
${services.map(line).join("\n")}

## Grenzen
Gebieds- en bedrijventerreinnamen zijn geografische context. De site claimt geen klanten, cases, samenwerkingen, garanties, certificeringen, responstijden of rankings.

## Blog
${blogPages.map((page) => `- ${page.title}: ${urlFor(page.slug)} — ${page.description}`).join("\n")}
`;
}

async function writePage(slug, html) {
  const target = pathFor(slug);
  await mkdir(new URL("./", target), { recursive: true });
  await writeFile(target, html, "utf8");
}

async function main() {
  for (const page of pages) await writePage(page.slug, renderPage(page));
  await writePage("", renderHome());
  await writeFile(new URL("sitemap.xml", root), renderSitemap(), "utf8");
  await writeFile(new URL("robots.txt", root), `User-agent: *\nAllow: /\n\nSitemap: ${base}/sitemap.xml\n`, "utf8");
  await writeFile(new URL("llms.txt", root), renderLlms(), "utf8");
  await rm(new URL("logistieke-beveiliging-sittard-geleen-holtum", root), { recursive: true, force: true });
}

await main();
